224	
225	// ---------------------------------------------------------------------------
226	// SQLiteFactStoreAdapter
227	// ---------------------------------------------------------------------------
228	
229	export class SQLiteFactStoreAdapter {
230	  private db: Database.Database;
231	  private factSeqCounters: Map<string, number> = new Map(); // eventId → 已生成的 Fact 序号
232	
233	  /**
234	   * @param dbPath   数据库文件路径，或 ':memory:' 用于内存数据库
235	   * @param projectId 项目 ID，用于初始化 project_state
236	   */
237	  constructor(dbPath: string, projectId: string = 'default') {
238	    // 创建数据库连接并启用 WAL 模式
239	    this.db = new Database(dbPath);
240	    this.db.pragma('journal_mode = WAL');
241	    this.db.pragma('foreign_keys = ON');
242	
243	    // 建表
244	    this.db.exec(DDL);
245	
246	    // 初始化项目状态（幂等）
247	    this.db.prepare(`
248	      INSERT OR IGNORE INTO project_state (project_id, state_version, current_chapter)
249	      VALUES (?, 0, 1)
250	    `).run(projectId);
251	  }
252	
253	  /** 获取底层 Database 实例（供同库的其他 Adapter 使用） */
254	  getDatabase(): Database.Database {
255	    return this.db;
256	  }
257	
258	  /** 关闭数据库连接 */
259	  close(): void {
260	    this.db.close();
261	  }
262	
263	  // -----------------------------------------------------------------------
264	  // 写入操作
265	  // -----------------------------------------------------------------------
266	
267	  /**
268	   * 断言新 Fact
269	   *
270	   * 自动生成 id 和 embeddingText（如果调用方未提供）。
271	   * causeEvent 和 validFrom 由调用方传入（通常来自 FactGroup）。
272	   */
273	  assert(fact: Omit<Fact, 'id'>): Fact {
274	    const { valueType, scalarType, textValue } = this.serializeFactValue(fact.value);
275	
276	    // 生成 Fact ID：fct_{type}_{chapter}_{seq}
277	    // 需要从 causeEvent 中提取 type 和 chapter
278	    // 例如 evt_tribulation_50 → type=tribulation, chapter=50
279	    const eventParts = fact.causeEvent.replace('evt_', '').split('_');
280	    const eventType = eventParts[0] ?? 'unknown';
281	    const chapter = eventParts[1] ?? '0';
282	    const eventSeq = eventParts.length > 2 ? eventParts[2] : undefined;
283	
284	    const counterKey = fact.causeEvent;
285	    const currentSeq = this.factSeqCounters.get(counterKey) ?? 0;
286	    const nextSeq = currentSeq + 1;
287	    this.factSeqCounters.set(counterKey, nextSeq);
288	
289	    // 构造 Fact ID
290	    let factId: string;
291	    if (eventSeq) {
292	      factId = `fct_${eventType}_${chapter}_${eventSeq}_${String(nextSeq).padStart(2, '0')}`;
293	    } else {
294	      factId = `fct_${eventType}_${chapter}_${String(nextSeq).padStart(2, '0')}`;
295	    }
296	
297	    const embeddingText = fact.embeddingText || '';
298	
299	    this.db.prepare(`
300	      INSERT INTO facts (id, subject, predicate, value_type, value_scalar_type, value_scalar, value_entity_ref,
301	                         certainty, cause_event, valid_from, valid_to, context, relation_kind, embedding_text)
302	      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
303	    `).run(
304	      factId,
305	      fact.subject,
306	      fact.predicate,
307	      valueType,
308	      scalarType ?? null,
309	      valueType === 'scalar' ? textValue : null,
310	      valueType === 'entity_ref' ? textValue : null,
311	      fact.certainty ?? 'canonical',
312	      fact.causeEvent,
313	      fact.validFrom,
314	      fact.validTo ?? null,
315	      fact.context ?? 'global',
316	      fact.relationKind ?? null,
317	      embeddingText,
318	    );
319	
320	    return this.rowToFact(this.db.prepare('SELECT * FROM facts WHERE id = ?').get(factId) as FactRow);
321	  }
322	
323	  /**
324	   * 撤回 Fact（设置 valid_to，不物理删除）
325	   */
326	  retract(factId: string, validTo: number): void {
327	    const result = this.db.prepare(`
328	      UPDATE facts SET valid_to = ? WHERE id = ? AND valid_to IS NULL
329	    `).run(validTo, factId);
330	    if (result.changes === 0) {
331	      throw new Error(`FACT_NOT_FOUND 或已失效: ${factId}`);
332	    }
333	  }
334	
335	  /**
336	   * 更新 Fact：retract 旧 + assert 新（保证不可变性）
337	   *
338	   * context 参数用于 exit_scope 场景（可选，省略则继承原 Fact 的 context）。
339	   */
340	  update(
341	    factId: string,
342	    newValue: FactValue,
343	    newCauseEvent: string,
344	    validFrom: number,
345	    context?: string,
346	  ): Fact {
347	    const oldFact = this.getById(factId);
348	    if (!oldFact) throw new Error(`FACT_NOT_FOUND: ${factId}`);
349	
350	    // 撤回旧 Fact
351	    this.retract(factId, validFrom);
352	
353	    // 断言新 Fact（继承旧 Fact 的大部分字段）
354	    const newFact = this.assert({
355	      subject: oldFact.subject,
356	      predicate: oldFact.predicate,
357	      value: newValue,
358	      certainty: oldFact.certainty,
359	      causeEvent: newCauseEvent,
360	      validFrom,
361	      validTo: null,
362	      context: context ?? oldFact.context,
363	      relationKind: oldFact.relationKind,
364	      embeddingText: oldFact.embeddingText,
365	      schemaVersion: oldFact.schemaVersion,
366	    });
367	
368	    return newFact;
369	  }
370	
371	  /**
372	   * 原子应用一组变更（SAVEPOINT 实现组内局部回滚）
373	   *
374	   * 调用约定：此方法在 commit_event Phase B 的 SQLite 事务内调用。
375	   * 返回 changeId → factId 映射表，供上层 KnowledgeStore / ThreadStore / audit_log 消费。
376	   */
377	  applyFactGroup(group: FactGroup): Map<string, string> {
378	    const idMap = new Map<string, string>();
379	
380	    this.db.prepare('SAVEPOINT factgroup_sp').run();
381	    try {
382	      for (const change of group.changes) {
383	        if (change.op === 'assert') {
384	          if (!change.payload) throw new Error('SCHEMA_VALIDATION_FAILED: assert 缺少 payload');
385	          if (change.payload.subject === undefined) throw new Error('SCHEMA_VALIDATION_FAILED: assert 缺少 subject');
386	          if (change.payload.predicate === undefined) throw new Error('SCHEMA_VALIDATION_FAILED: assert 缺少 predicate');
387	          if (change.payload.value === undefined) throw new Error('SCHEMA_VALIDATION_FAILED: assert 缺少 value');
388	          if (change.payload.validFrom === undefined) throw new Error('SCHEMA_VALIDATION_FAILED: assert 缺少 validFrom');
389	
390	          const newFact = this.assert({
391	            subject: change.payload.subject,
392	            predicate: change.payload.predicate,
393	            value: change.payload.value,
394	            certainty: change.payload.certainty ?? 'canonical',
395	            causeEvent: group.causeEvent,
396	            validFrom: change.payload.validFrom,
397	            validTo: change.payload.validTo ?? null,
398	            context: change.payload.context ?? 'global',
399	            relationKind: change.payload.relationKind,
400	            embeddingText: '',
401	            schemaVersion: change.payload.schemaVersion ?? 1,
402	          });
403	          if (change.changeId) {
404	            idMap.set(change.changeId, newFact.id);
405	          }
406	        } else if (change.op === 'retract') {
407	          if (!change.targetFactId) throw new Error('SCHEMA_VALIDATION_FAILED: retract 缺少 targetFactId');
408	          if (!change.payload || typeof change.payload.validTo !== 'number') {
409	            throw new Error('SCHEMA_VALIDATION_FAILED: retract 缺少 validTo');
410	          }
411	
412	          const targetId = change.targetFactId;
413	          const targetFact = this.getById(targetId);
414	          if (!targetFact) throw new Error(`FACT_NOT_FOUND: ${targetId}`);
415	          if (targetFact.validTo !== null) throw new Error(`FACT_NOT_CURRENT: ${targetId}`);
416	          if (change.payload.context && targetFact.context !== change.payload.context) {
417	            throw new Error(`SCOPE_FACT_MISMATCH: ${targetId}`);
418	          }
419	          this.retract(targetId, change.payload.validTo);
420	          if (change.changeId) {
421	            idMap.set(change.changeId, targetId);
422	          }
423	        } else if (change.op === 'update') {
424	          if (!change.targetFactId) throw new Error('SCHEMA_VALIDATION_FAILED: update 缺少 targetFactId');
425	          if (!change.payload || change.payload.validFrom === undefined) {
426	            throw new Error('SCHEMA_VALIDATION_FAILED: update 缺少 validFrom');
427	          }
428	
429	          const targetId = change.targetFactId;
430	          const targetFact = this.getById(targetId);
431	          if (!targetFact) throw new Error(`FACT_NOT_FOUND: ${targetId}`);
432	          if (targetFact.validTo !== null) throw new Error(`FACT_NOT_CURRENT: ${targetId}`);
433	          if (change.payload.context && targetFact.context !== change.payload.context) {
434	            throw new Error(`SCOPE_FACT_MISMATCH: ${targetId}`);
435	          }
436	
437	          this.retract(targetId, change.payload.validFrom);
438	          const newFact = this.assert({
439	            subject: change.payload.subject ?? targetFact.subject,
440	            predicate: change.payload.predicate ?? targetFact.predicate,
441	            value: change.payload.value !== undefined ? change.payload.value : targetFact.value,
442	            certainty: change.payload.certainty ?? targetFact.certainty,
443	            causeEvent: group.causeEvent,
444	            validFrom: change.payload.validFrom,
445	            validTo: null,
446	            context: change.payload.context ?? targetFact.context,
447	            relationKind: change.payload.relationKind ?? targetFact.relationKind,
448	            embeddingText: targetFact.embeddingText,
449	            schemaVersion: change.payload.schemaVersion ?? targetFact.schemaVersion,
450	          });
451	          if (change.changeId) {
452	            idMap.set(change.changeId, newFact.id);
453	          }
454	        }
455	      }
456	      this.db.prepare('RELEASE factgroup_sp').run();
457	    } catch (err) {
458	      this.db.prepare('ROLLBACK TO factgroup_sp').run();
459	      throw err;
460	    }
461	
462	    return idMap;
463	  }
464	
465	  /**
466	   * 物理删除 Fact（仅供事务回滚使用，不对外暴露）
467	   */
468	  forceRemove(factId: string): void {
469	    this.db.prepare('DELETE FROM facts WHERE id = ?').run(factId);
470	  }
471	
472	  // -----------------------------------------------------------------------
473	  // 查询操作
474	  // -----------------------------------------------------------------------
475	
476	  /**
477	   * 通用多维查询
478	   *
479	   * 时间切片过滤规则（§4.3）：
480	   *   fact.validFrom <= query.atChapter
481	   *   AND (query.mode='history' OR fact.validTo IS NULL OR fact.validTo > query.atChapter)
482	   */
483	  query(query: FactQuery): Fact[] {
484	    const conditions: string[] = [];
485	    const params: unknown[] = [];
486	
487	    if (query.subject) {
488	      conditions.push('subject = ?');
489	      params.push(query.subject);
490	    }
491	    if (query.predicate) {
492	      conditions.push('predicate = ?');
493	      params.push(query.predicate);
494	    }
495	
496	    // 时间切片
497	    if (query.atChapter !== undefined) {
498	      conditions.push('valid_from <= ?');
499	      params.push(query.atChapter);
500	      if (query.mode !== 'history') {
501	        // current 模式：只查当前有效的 Fact
502	        conditions.push('(valid_to IS NULL OR valid_to > ?)');
503	        params.push(query.atChapter);
504	      }
505	    }
506	
507	    // 确定性过滤
508	    if (query.certainties && query.certainties.length > 0) {
509	      conditions.push(`certainty IN (${query.certainties.map(() => '?').join(',')})`);
510	      params.push(...query.certainties);
511	    } else {
512	      // 默认只查 canonical 和 contested
513	      conditions.push("certainty IN ('canonical', 'contested')");
514	    }
515	
516	    // 关系语义过滤
517	    if (query.relationKind) {
518	      conditions.push('relation_kind = ?');
519	      params.push(query.relationKind);
520	    }
521	
522	    // 反向关系查询
523	    if (query.valueEntityRef) {
524	      conditions.push('value_type = ? AND value_entity_ref = ?');
525	      params.push('entity_ref', query.valueEntityRef);
526	    }
527	
528	    // 作用域过滤
529	    if (query.context && query.context !== 'global' && query.includeInherited !== false) {
530	      // 包含继承：自身 context + global 的兜底
531	      conditions.push('(context = ? OR context = ?)');
532	      params.push(query.context, 'global');
533	    } else if (query.context) {
534	      conditions.push('context = ?');
535	      params.push(query.context);
536	    }
537	
538	    // 非活跃 Fact 显式过滤
539	    if (query.includeInactive !== true && query.mode !== 'history') {
540	      // 默认排除已失效的 Fact（valid_to 已过）
541	    }
542	
543	    const whereClause = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';
544	    const rows = this.db.prepare(`SELECT * FROM facts ${whereClause} ORDER BY valid_from DESC`).all(...params) as FactRow[];
545	    return rows.map(r => this.rowToFact(r));
546	  }
547	
548	  /**
549	   * 实体在某章节时刻的状态快照
550	   *
551	   * 返回 { predicate: value } 的去重字典（同 predicate 取最新 validFrom 的值）。
552	   */
553	  getSnapshot(subject: string, atChapter: number): Record<string, FactValue> {
554	    const facts = this.query({
555	      subject,
556	      atChapter,
557	      certainties: ['canonical', 'contested'],
558	      mode: 'current',
559	    });
560	
561	    // 同 predicate 取 validFrom 最新的值（最近一次变更）
562	    const snapshot: Record<string, FactValue> = {};
563	    for (const f of facts) {
564	      if (!(f.predicate in snapshot)) {
565	        snapshot[f.predicate] = f.value;
566	      }
567	    }
568	    return snapshot;
569	  }
570	
571	  /**
572	   * 按事件追溯其产生的所有 Fact
573	   */
574	  getFactsByEvent(eventId: string): Fact[] {
575	    const rows = this.db.prepare(
576	      'SELECT * FROM facts WHERE cause_event = ? ORDER BY id'
577	    ).all(eventId) as FactRow[];
578	    return rows.map(r => this.rowToFact(r));
579	  }
580	
581	  /**
582	   * 按 ID 获取单条 Fact
583	   */
584	  getById(factId: string): Fact | undefined {
585	    const row = this.db.prepare('SELECT * FROM facts WHERE id = ?').get(factId) as FactRow | undefined;
586	    return row ? this.rowToFact(row) : undefined;
587	  }
588	
589	  /**
590	   * 查询所有指向某实体的关系 Fact（反向查询）
591	   */
592	  getRelationsTargeting(entityId: string, atChapter?: number): Fact[] {
593	    const conditions: string[] = ['value_type = ?', 'value_entity_ref = ?'];
594	    const params: unknown[] = ['entity_ref', entityId];
595	
596	    if (atChapter !== undefined) {
597	      conditions.push('valid_from <= ?');
598	      params.push(atChapter);
599	      conditions.push('(valid_to IS NULL OR valid_to > ?)');
600	      params.push(atChapter);
601	    }
602	
603	    const rows = this.db.prepare(
604	      `SELECT * FROM facts WHERE ${conditions.join(' AND ')} ORDER BY valid_from DESC`
605	    ).all(...params) as FactRow[];
606	    return rows.map(r => this.rowToFact(r));
607	  }
608	
609	  // -----------------------------------------------------------------------
610	  // 辅助方法
611	  // -----------------------------------------------------------------------
612	
613	  /**
614	   * 将 SQLite 行转换为 Fact 对象
615	   */
616	  private rowToFact(row: FactRow): Fact {
617	    return {
618	      id: row.id,
619	      subject: row.subject,
620	      predicate: row.predicate,
621	      value: this.deserializeFactValue(row),
622	      certainty: row.certainty as Certainty,
623	      causeEvent: row.cause_event,
624	      validFrom: row.valid_from,
625	      validTo: row.valid_to,
626	      context: row.context,
627	      relationKind: (row.relation_kind as Fact['relationKind']) ?? undefined,
628	      embeddingText: row.embedding_text,
629	      schemaVersion: row.schema_version,
630	    };
631	  }
632	
633	  /**
634	   * 序列化 FactValue → SQLite 存储格式
635	   */
636	  private serializeFactValue(value: FactValue): {
637	    valueType: 'scalar' | 'entity_ref';
638	    scalarType: FactScalarType | null;
639	    textValue: string;
640	  } {
641	    const serialized = serializeFactValue(value);
642	    return {
643	      valueType: serialized.valueType,
644	      scalarType: serialized.scalarType ?? null,
645	      textValue: serialized.textValue,
646	    };
647	  }
648	
649	  /**
650	   * 从 SQLite 行反序列化 FactValue
651	   */
652	  private deserializeFactValue(row: FactRow): FactValue {
653	    return deserializeFactValue({
654	      valueType: row.value_type,
655	      scalarType: row.value_scalar_type ?? undefined,
656	      textValue: row.value_type === 'entity_ref' ? (row.value_entity_ref ?? '') : (row.value_scalar ?? ''),
657	    });
658	  }
659	
660	  /**
661	   * 获取项目当前乐观锁版本号（供 commit_event Phase B 使用）
662	   */
663	  getStateVersion(projectId: string): number {
664	    const row = this.db.prepare(
665	      'SELECT state_version FROM project_state WHERE project_id = ?'
666	    ).get(projectId) as { state_version: number } | undefined;
667	    return row?.state_version ?? 0;
668	  }
669	
670	  /**
671	   * 条件更新乐观锁版本号（Phase B 第一步）
672	   *
673	   * @returns 更新行数（0 = 版本冲突，1 = 成功）
674	   */
675	  tryUpdateStateVersion(projectId: string, expectedVersion: number): boolean {
676	    const result = this.db.prepare(
677	      `UPDATE project_state SET state_version = state_version + 1, updated_at = datetime('now')
678	       WHERE project_id = ? AND state_version = ?`
679	    ).run(projectId, expectedVersion);
680	    return result.changes === 1;
681	  }
682	}
