1	// =============================================================================
2	// SQLiteKnowledgeStoreAdapter —— KnowledgeStore 接口的 SQLite 实现
3	// =============================================================================
4	// Phase 1 最小版本：表结构 + create / batchCreate / getLatest / getByFactId。
5	// seal/restore/decay/soul_read/implant 的写入编排由 ProposalManager 在 Phase B 完成。
6	//
7	// 设计原则：
8	//   - Event Sourcing 不可变：永远不 DELETE / UPDATE knowledge 表记录，只 INSERT 新记录
9	//   - "取最新"查询：ORDER BY known_since DESC, rowid DESC LIMIT 1
10	//   - rowid tiebreaker：同章节内显式操作（seal/implant）晚于自动推导（propagation）
11	//   - 与 FactStore 共享同一个 SQLite 连接（同库不同表）
12	//
13	// 与架构文档的对应关系：
14	//   §3.6  Knowledge 双流写入     → 与 Fact 流并行的认知事件流
15	//   §4.3.4 KnowledgeStore 接口    → 完整接口定义
16	//   §10.1 写入流                  → Phase B 事务内原子写入
17	//   附录 E.7 knowledge 表         → DDL 已在 FactStore 适配器中创建
18	// =============================================================================
19	
20	import type Database from 'better-sqlite3';
21	import type { Knowledge, KnowledgeFilter, KnowledgeSource } from '../../types.js';
22	
23	// ---------------------------------------------------------------------------
24	// SQLite 行类型
25	// ---------------------------------------------------------------------------
26	
27	interface KnowledgeRow {
28	  id: string;
29	  fact_id: string;
30	  entity_id: string;
31	  known_since: number;
32	  source: string;
33	  confidence: number;
34	  previous_confidence: number | null;
35	  updated_at_event: string | null;
36	}
37	
38	// ---------------------------------------------------------------------------
39	// SQLiteKnowledgeStoreAdapter
40	// ---------------------------------------------------------------------------
41	
42	export class SQLiteKnowledgeStoreAdapter {
43	  private db: Database.Database;
44	
45	  /**
46	   * @param db 共享的 better-sqlite3 Database 实例（与 FactStore 同库）
47	   *           DDL 已由 SQLiteFactStoreAdapter 在初始化时创建
48	   */
49	  constructor(db: Database.Database) {
50	    this.db = db;
51	  }
52	
53	  // -----------------------------------------------------------------------
54	  // 写入操作
55	  // -----------------------------------------------------------------------
56	
57	  /**
58	   * 创建单条 Knowledge 记录
59	   *
60	   * 自动生成 ID：kno_{knower}_{factSeq}
61	   * knower 为 entityId 去掉 ent_ 前缀的部分
62	   * factSeq 为 factId 去掉 fct_ 前缀的部分
63	   */
64	  create(knowledge: Omit<Knowledge, 'id'>): Knowledge {
65	    const id = this.generateId(knowledge.entityId, knowledge.factId);
66	
67	    this.db.prepare(`
68	      INSERT INTO knowledge (id, fact_id, entity_id, known_since, source, confidence, previous_confidence, updated_at_event)
69	      VALUES (?, ?, ?, ?, ?, ?, ?, ?)
70	    `).run(
71	      id,
72	      knowledge.factId,
73	      knowledge.entityId,
74	      knowledge.knownSince,
75	      knowledge.source,
76	      knowledge.confidence,
77	      knowledge.previousConfidence ?? null,
78	      knowledge.updatedAtEvent ?? null,
79	    );
80	
81	    return this.rowToKnowledge(
82	      this.db.prepare('SELECT * FROM knowledge WHERE id = ?').get(id) as KnowledgeRow
83	    );
84	  }
85	
86	  /**
87	   * 批量创建 Knowledge 记录（commit_event 时一次性写入多条）
88	   *
89	   * 所有记录在同一事务中写入，保证原子性。
90	   */
91	  batchCreate(entries: Omit<Knowledge, 'id'>[]): Knowledge[] {
92	    const stmt = this.db.prepare(`
93	      INSERT INTO knowledge (id, fact_id, entity_id, known_since, source, confidence, previous_confidence, updated_at_event)
94	      VALUES (?, ?, ?, ?, ?, ?, ?, ?)
95	    `);
96	
97	    const results: Knowledge[] = [];
98	    for (const entry of entries) {
99	      const id = this.generateId(entry.entityId, entry.factId);
100	      stmt.run(
101	        id,
102	        entry.factId,
103	        entry.entityId,
104	        entry.knownSince,
105	        entry.source,
106	        entry.confidence,
107	        entry.previousConfidence ?? null,
108	        entry.updatedAtEvent ?? null,
109	      );
110	      // 回读已写入的记录（同一事务内可见）
111	      const row = this.db.prepare('SELECT * FROM knowledge WHERE id = ?').get(id) as KnowledgeRow;
112	      results.push(this.rowToKnowledge(row));
113	    }
114	
115	    return results;
116	  }
117	
118	  // -----------------------------------------------------------------------
119	  // 查询操作
120	  // -----------------------------------------------------------------------
121	
122	  /**
123	   * 查询某实体在指定章节知道的所有 Fact（取最新一条 Knowledge 记录的 confidence > 0）
124	   *
125	   * "取最新"查询模板：
126	   *   WHERE entity_id = ? AND known_since <= ? ORDER BY known_since DESC, rowid DESC LIMIT 1
127	   */
128	  getKnownFacts(entityId: string, atChapter?: number): Knowledge[] {
129	    // 使用子查询：对每个 (entity_id, fact_id) 组合取最新一条
130	    let sql: string;
131	    const params: unknown[] = [entityId];
132	
133	    if (atChapter !== undefined) {
134	      sql = `
135	        SELECT k.* FROM knowledge k
136	        INNER JOIN (
137	          SELECT entity_id, fact_id, MAX(known_since) as max_known, MAX(rowid) as max_rowid
138	          FROM knowledge
139	          WHERE entity_id = ? AND known_since <= ?
140	          GROUP BY entity_id, fact_id
141	        ) latest ON k.entity_id = latest.entity_id AND k.fact_id = latest.fact_id
142	                  AND k.known_since = latest.max_known AND k.rowid = latest.max_rowid
143	        WHERE k.confidence > 0
144	      `;
145	      params.push(atChapter);
146	    } else {
147	      sql = `
148	        SELECT k.* FROM knowledge k
149	        INNER JOIN (
150	          SELECT entity_id, fact_id, MAX(known_since) as max_known, MAX(rowid) as max_rowid
151	          FROM knowledge
152	          WHERE entity_id = ?
153	          GROUP BY entity_id, fact_id
154	        ) latest ON k.entity_id = latest.entity_id AND k.fact_id = latest.fact_id
155	                  AND k.known_since = latest.max_known AND k.rowid = latest.max_rowid
156	        WHERE k.confidence > 0
157	      `;
158	    }
159	
160	    const rows = this.db.prepare(sql).all(...params) as KnowledgeRow[];
161	    return rows.map(r => this.rowToKnowledge(r));
162	  }
163	
164	  /**
165	   * 查询某实体知道的所有活跃 Fact（过滤掉指向 contested/orphaned Fact 的 Knowledge）
166	   *
167	   * 用于检索管线 Step 5 的知识感知过滤。
168	   * JOIN facts 表确保只返回指向 canonical/potential Fact 的 Knowledge。
169	   */
170	  getActiveKnowledge(entityId: string, atChapter?: number): Knowledge[] {
171	    let sql: string;
172	    const params: unknown[] = [entityId];
173	
174	    if (atChapter !== undefined) {
175	      sql = `
176	        SELECT k.* FROM knowledge k
177	        INNER JOIN facts f ON k.fact_id = f.id
178	        INNER JOIN (
179	          SELECT k2.entity_id, k2.fact_id, MAX(k2.known_since) as max_known, MAX(k2.rowid) as max_rowid
180	          FROM knowledge k2
181	          WHERE k2.entity_id = ? AND k2.known_since <= ?
182	          GROUP BY k2.entity_id, k2.fact_id
183	        ) latest ON k.entity_id = latest.entity_id AND k.fact_id = latest.fact_id
184	                  AND k.known_since = latest.max_known AND k.rowid = latest.max_rowid
185	        WHERE k.confidence > 0 AND f.certainty IN ('canonical', 'potential')
186	      `;
187	      params.push(atChapter);
188	    } else {
189	      sql = `
190	        SELECT k.* FROM knowledge k
191	        INNER JOIN facts f ON k.fact_id = f.id
192	        INNER JOIN (
193	          SELECT k2.entity_id, k2.fact_id, MAX(k2.known_since) as max_known, MAX(k2.rowid) as max_rowid
194	          FROM knowledge k2
195	          WHERE k2.entity_id = ?
196	          GROUP BY k2.entity_id, k2.fact_id
197	        ) latest ON k.entity_id = latest.entity_id AND k.fact_id = latest.fact_id
198	                  AND k.known_since = latest.max_known AND k.rowid = latest.max_rowid
199	        WHERE k.confidence > 0 AND f.certainty IN ('canonical', 'potential')
200	      `;
201	    }
202	
203	    const rows = this.db.prepare(sql).all(...params) as KnowledgeRow[];
204	    return rows.map(r => this.rowToKnowledge(r));
205	  }
206	
207	  /**
208	   * 查询某条 Fact 被哪些实体知晓（取最新一条认知记录，confidence > 0）
209	   */
210	  getKnowersOfFact(factId: string): Knowledge[] {
211	    const sql = `
212	      SELECT k.* FROM knowledge k
213	      INNER JOIN (
214	        SELECT entity_id, fact_id, MAX(known_since) as max_known, MAX(rowid) as max_rowid
215	        FROM knowledge
216	        WHERE fact_id = ?
217	        GROUP BY entity_id, fact_id
218	      ) latest ON k.entity_id = latest.entity_id AND k.fact_id = latest.fact_id
219	                AND k.known_since = latest.max_known AND k.rowid = latest.max_rowid
220	      WHERE k.confidence > 0
221	    `;
222	    const rows = this.db.prepare(sql).all(factId) as KnowledgeRow[];
223	    return rows.map(r => this.rowToKnowledge(r));
224	  }
225	
226	  /**
227	   * 查询某 Fact 的全部认知记录（Retcon 级联扫描使用，含历史记录）
228	   *
229	   * 与 getKnowersOfFact 的区别：不过滤 confidence > 0，返回全部历史记录。
230	   */
231	  getByFactId(factId: string): Knowledge[] {
232	    const rows = this.db.prepare(
233	      'SELECT * FROM knowledge WHERE fact_id = ? ORDER BY known_since DESC, rowid DESC'
234	    ).all(factId) as KnowledgeRow[];
235	    return rows.map(r => this.rowToKnowledge(r));
236	  }
237	
238	  /**
239	   * 更新确信度（作者订正时使用）
240	   *
241	   * ⚠ 不直接 UPDATE！遵循 Event Sourcing 原则：INSERT 新记录。
242	   * 通过 generateId 自动获取下一个可用序号。
243	   */
244	  updateConfidence(knowledgeId: string, confidence: number, updatedByEvent?: string): void {
245	    const existing = this.db.prepare('SELECT * FROM knowledge WHERE id = ?').get(knowledgeId) as KnowledgeRow | undefined;
246	    if (!existing) throw new Error(`KNOWLEDGE_NOT_FOUND: ${knowledgeId}`);
247	
248	    // INSERT 新记录（confidence 变更，其他字段继承）
249	    // 委托 create 以复用 generateId 的消歧逻辑
250	    this.create({
251	      factId: existing.fact_id,
252	      entityId: existing.entity_id,
253	      knownSince: existing.known_since,
254	      source: existing.source as KnowledgeSource,
255	      confidence,
256	      previousConfidence: existing.confidence,
257	      updatedAtEvent: updatedByEvent ?? undefined,
258	    });
259	  }
260	
261	  /**
262	   * 通用多条件查询
263	   */
264	  query(filter: KnowledgeFilter): Knowledge[] {
265	    const conditions: string[] = [];
266	    const params: unknown[] = [];
267	
268	    if (filter.entityId) {
269	      conditions.push('entity_id = ?');
270	      params.push(filter.entityId);
271	    }
272	    if (filter.factId) {
273	      conditions.push('fact_id = ?');
274	      params.push(filter.factId);
275	    }
276	    if (filter.source && filter.source.length > 0) {
277	      conditions.push(`source IN (${filter.source.map(() => '?').join(',')})`);
278	      params.push(...filter.source);
279	    }
280	    if (filter.minConfidence !== undefined) {
281	      conditions.push('confidence >= ?');
282	      params.push(filter.minConfidence);
283	    }
284	    if (filter.atChapter !== undefined) {
285	      conditions.push('known_since <= ?');
286	      params.push(filter.atChapter);
287	    }
288	
289	    const whereClause = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';
290	    const rows = this.db.prepare(
291	      `SELECT * FROM knowledge ${whereClause} ORDER BY known_since DESC, rowid DESC`
292	    ).all(...params) as KnowledgeRow[];
293	
294	    return rows.map(r => this.rowToKnowledge(r));
295	  }
296	
297	  // -----------------------------------------------------------------------
298	  // 辅助方法
299	  // -----------------------------------------------------------------------
300	
301	  /**
302	   * 生成 Knowledge ID：kno_{knower}_{factRef}[_{seq}]
303	   *
