1	// =============================================================================
2	// SQLiteEventStoreAdapter —— EventStore 接口的 SQLite 实现
3	// =============================================================================
4	// 事件持久化存储，支持 Retcon BFS 级联遍历和事件溯源。
5	// 与 FactStore 共享同一个 SQLite 连接（同库不同表）。
6	// =============================================================================
7	
8	import type Database from 'better-sqlite3';
9	import type { NarrativeEvent, EventKindFilter } from '../../types.js';
10	
11	interface EventRow {
12	  id: string;
13	  kind: string;
14	  type: string;
15	  chapter: number;
16	  description: string;
17	  params_json: string;
18	  context: string;
19	  timestamp: string;
20	  status: string;
21	  fact_group_id: string;
22	  resolved_threads: string;
23	  dependencies_json: string;
24	}
25	
26	export class SQLiteEventStoreAdapter {
27	  private db: Database.Database;
28	
29	  constructor(db: Database.Database) {
30	    this.db = db;
31	  }
32	
33	  create(event: Omit<NarrativeEvent, 'id'>): NarrativeEvent {
34	    // 生成事件 ID
35	    const seq = (this.db.prepare('SELECT COUNT(*) as cnt FROM events').get() as { cnt: number }).cnt + 1;
36	    const id = `evt_${event.type}_${event.chapter}_${String(seq).padStart(2, '0')}`;
37	
38	    this.db.prepare(`
39	      INSERT INTO events (id, kind, type, chapter, description, params_json, context, fact_group_id, resolved_threads, dependencies_json)
40	      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
41	    `).run(
42	      id,
43	      event.kind ?? 'business',
44	      event.type,
45	      event.chapter,
46	      event.description,
47	      JSON.stringify(event.params ?? {}),
48	      event.context ?? 'global',
49	      id, // fact_group_id = event id (1:1)
50	      JSON.stringify(event.resolvedThreads ?? []),
51	      JSON.stringify(event.dependentFactIds ?? []),
52	    );
53	
54	    return this.rowToEvent(
55	      this.db.prepare('SELECT * FROM events WHERE id = ?').get(id) as EventRow
56	    );
57	  }
58	
59	  getById(eventId: string): NarrativeEvent | undefined {
60	    const row = this.db.prepare('SELECT * FROM events WHERE id = ?').get(eventId) as EventRow | undefined;
61	    return row ? this.rowToEvent(row) : undefined;
62	  }
63	
64	  getByChapterRange(fromChapter: number, toChapter?: number, kind: EventKindFilter = 'business'): NarrativeEvent[] {
65	    let sql = 'SELECT * FROM events WHERE chapter >= ?';
66	    const params: unknown[] = [fromChapter];
67	    if (toChapter !== undefined) { sql += ' AND chapter <= ?'; params.push(toChapter); }
68	    if (kind !== 'all') { sql += ' AND kind = ?'; params.push(kind); }
69	    sql += ' ORDER BY chapter ASC';
70	    const rows = this.db.prepare(sql).all(...params) as EventRow[];
71	    return rows.map(r => this.rowToEvent(r));
72	  }
73	
74	  getBySubject(entityId: string, fromChapter?: number, kind: EventKindFilter = 'business'): NarrativeEvent[] {
75	    let sql = "SELECT * FROM events WHERE json_extract(params_json, '$.subject') = ?";
76	    const params: unknown[] = [entityId];
77	    if (fromChapter !== undefined) { sql += ' AND chapter >= ?'; params.push(fromChapter); }
78	    if (kind !== 'all') { sql += ' AND kind = ?'; params.push(kind); }
79	    sql += ' ORDER BY chapter ASC';
80	    const rows = this.db.prepare(sql).all(...params) as EventRow[];
81	    return rows.map(r => this.rowToEvent(r));
82	  }
83	
84	  getByType(eventType: string, fromChapter?: number, kind: EventKindFilter = 'business'): NarrativeEvent[] {
85	    let sql = 'SELECT * FROM events WHERE type = ?';
86	    const params: unknown[] = [eventType];
87	    if (fromChapter !== undefined) { sql += ' AND chapter >= ?'; params.push(fromChapter); }
88	    if (kind !== 'all') { sql += ' AND kind = ?'; params.push(kind); }
89	    sql += ' ORDER BY chapter ASC';
90	    const rows = this.db.prepare(sql).all(...params) as EventRow[];
91	    return rows.map(r => this.rowToEvent(r));
92	  }
93	
94	  getByDependentFactIds(factIds: string[], kind: EventKindFilter = 'business'): NarrativeEvent[] {
95	    const placeholders = factIds.map(() => '?').join(',');
96	    let sql = `SELECT DISTINCT e.* FROM events e
97	      INNER JOIN event_dependencies ed ON e.id = ed.event_id
98	      WHERE ed.fact_id IN (${placeholders})`;
99	    const params: unknown[] = [...factIds];
100	    if (kind !== 'all') { sql += ' AND e.kind = ?'; params.push(kind); }
101	    sql += ' ORDER BY e.chapter ASC';
102	    const rows = this.db.prepare(sql).all(...params) as EventRow[];
103	    return rows.map(r => this.rowToEvent(r));
104	  }
105	
